const MCP_CALL_LOG_FIELD_MAX_CHARS: usize = 4096;

/// MCP tool 执行状态。
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum McpToolExecutionStatus {
    /// 工具执行成功。
    Succeeded,
    /// 工具执行失败。
    Failed,
}

/// MCP 工具调用执行结果。
#[derive(Debug, Clone)]
struct ToolExecutionResult {
    pub(super) status: McpToolExecutionStatus,
    pub(super) result_summary: Option<String>,
    pub(super) error: Option<String>,
    pub(super) structured_result: Option<Value>,
    pub(super) entities: Vec<Value>,
    pub(super) error_kind: Option<String>,
    pub(super) recoverable: bool,
    pub(super) next_hints: Vec<String>,
}

impl Default for ToolExecutionResult {
    fn default() -> Self {
        Self {
            status: McpToolExecutionStatus::Failed,
            result_summary: None,
            error: None,
            structured_result: None,
            entities: Vec::new(),
            error_kind: None,
            recoverable: false,
            next_hints: Vec::new(),
        }
    }
}

/// MCP `tools/call` 直接执行输出。
#[derive(Debug, Clone)]
pub struct McpToolExecutionOutput {
    pub status: McpToolExecutionStatus,
    pub summary: Option<String>,
    pub error: Option<String>,
    pub data: Value,
    pub entities: Vec<Value>,
    pub error_kind: Option<String>,
    pub recoverable: bool,
    pub next_hints: Vec<String>,
}

impl From<ToolExecutionResult> for McpToolExecutionOutput {
    fn from(result: ToolExecutionResult) -> Self {
        Self {
            status: result.status,
            summary: result.result_summary,
            error: result.error,
            data: result.structured_result.unwrap_or_else(|| json!({})),
            entities: result.entities,
            error_kind: result.error_kind,
            recoverable: result.recoverable,
            next_hints: result.next_hints,
        }
    }
}

/// MCP tools/call 直接执行器。
#[derive(Debug, Clone, Default)]
pub struct McpToolExecutorService;

/// MCP 工具执行时需要访问的运行时服务集合。
#[derive(Debug, Clone, Copy)]
pub struct McpToolExecutionContext<'a> {
    /// 终端会话管理服务。
    pub terminals: &'a TerminalManager,
    /// 外部 Agent session 文件服务。
    pub agent_sessions: &'a AgentSessionService,
    /// Agent session 到目标终端的运行态绑定解析服务。
    pub terminal_session_bindings: &'a TerminalSessionBindingService,
    /// 命令历史服务。
    pub command_history: &'a CommandHistoryService,
    /// 命令历史和命令建议专用 SQLite 存储。
    pub command_store: &'a CommandSqliteStore,
    /// 应用设置服务。
    pub settings: &'a SettingsService,
    /// 远程主机配置服务。
    pub remote_hosts: &'a RemoteHostService,
    /// 服务器信息采集服务。
    pub server_info: &'a ServerInfoService,
    /// 本地诊断服务。
    pub diagnostics: &'a DiagnosticsService,
    /// SFTP 文件工具服务。
    pub sftp: &'a SftpService,
    /// Docker/Podman 容器服务。
    pub docker_hosts: &'a DockerHostService,
    /// SSH 端口转发服务。
    pub port_forwards: &'a PortForwardService,
    /// 本机共享网络代理服务。
    pub local_network_proxy: &'a LocalNetworkProxyService,
    /// SSH 非交互命令服务。
    pub ssh_commands: &'a SshCommandService,
    /// 本地数据目录集合。
    pub paths: &'a KerminalPaths,
    /// Runtime file store entry for port-forward and local file audit state.
    pub storage: &'a RuntimeFileStore,
}

impl McpToolExecutorService {
    /// 创建 MCP tool 直接执行器。
    pub fn new() -> Self {
        Self
    }

    /// 直接执行一次 MCP tool 调用，不创建 pending invocation，也不执行二次确认策略。
    pub async fn execute(
        &self,
        context: McpToolExecutionContext<'_>,
        tools: &[ToolDefinition],
        tool_id: &str,
        arguments: Value,
    ) -> AppResult<McpToolExecutionOutput> {
        let tool_id = tool_id.trim();
        if tool_id.is_empty() {
            return Err(AppError::InvalidInput("工具 id 不能为空".to_owned()));
        }

        let tool = find_enabled_tool(tools, tool_id)?;
        let arguments = normalized_arguments(arguments)?;
        validate_required_arguments(&tool, &arguments)?;
        let result = execute_tool(&context, &tool.id, &arguments).await;
        append_agent_mcp_call_log(&context, &tool.id, &arguments, &result);
        Ok(result.into())
    }
}

fn append_agent_mcp_call_log(
    context: &McpToolExecutionContext<'_>,
    tool_id: &str,
    arguments: &serde_json::Map<String, Value>,
    result: &ToolExecutionResult,
) {
    let Some(agent_session_id) = arguments.get("agentSessionId").and_then(Value::as_str) else {
        return;
    };
    let Ok(agent_session_id) = AgentSessionId::new(agent_session_id.to_owned()) else {
        return;
    };
    let status = match result.status {
        McpToolExecutionStatus::Succeeded => "succeeded",
        McpToolExecutionStatus::Failed => "failed",
    };
    let entry = AgentMcpCallLogEntry {
        schema_version: AGENT_SESSION_SCHEMA_VERSION,
        agent_session_id,
        tool_id: tool_id.to_owned(),
        status: status.to_owned(),
        summary: mcp_call_log_field(result.result_summary.as_deref()),
        error: mcp_call_log_field(result.error.as_deref()),
        generated_at: current_unix_timestamp(),
    };
    let _ = context.agent_sessions.append_mcp_call_log(&entry);
}

fn mcp_call_log_field(value: Option<&str>) -> Option<String> {
    value.map(|value| {
        let (redacted, _) = redact_terminal_text(value);
        truncate_log_field(&redacted, MCP_CALL_LOG_FIELD_MAX_CHARS)
    })
}

fn truncate_log_field(value: &str, max_chars: usize) -> String {
    let mut chars = value.chars();
    let truncated = chars.by_ref().take(max_chars).collect::<String>();
    if chars.next().is_some() {
        format!("{truncated}...")
    } else {
        truncated
    }
}

fn current_unix_timestamp() -> String {
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|duration| duration.as_secs().to_string())
        .unwrap_or_else(|_| "0".to_owned())
}

fn find_enabled_tool(tools: &[ToolDefinition], tool_id: &str) -> AppResult<ToolDefinition> {
    let tool = tools
        .iter()
        .find(|tool| tool.id == tool_id)
        .cloned()
        .ok_or_else(|| AppError::NotFound(format!("工具不存在: {tool_id}")))?;

    if !tool.enabled {
        return Err(AppError::InvalidInput(format!("工具未启用: {tool_id}")));
    }

    Ok(tool)
}

fn normalized_arguments(value: Value) -> AppResult<serde_json::Map<String, Value>> {
    match value {
        Value::Object(map) => Ok(map),
        Value::Null => Ok(serde_json::Map::new()),
        _ => Err(AppError::InvalidInput(
            "工具参数必须是 JSON object".to_owned(),
        )),
    }
}

fn validate_required_arguments(
    tool: &ToolDefinition,
    arguments: &serde_json::Map<String, Value>,
) -> AppResult<()> {
    let required = tool
        .input_schema
        .get("required")
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
        .filter_map(Value::as_str);

    for key in required {
        if !arguments.contains_key(key) || arguments.get(key).is_some_and(Value::is_null) {
            return Err(AppError::InvalidInput(format!(
                "工具 {} 缺少必填参数: {}",
                tool.id, key
            )));
        }
    }

    Ok(())
}

pub(super) fn collapse_whitespace(value: &str) -> String {
    value.split_whitespace().collect::<Vec<_>>().join(" ")
}

pub(super) fn truncate_string(value: &str) -> String {
    const MAX_CHARS: usize = 160;
    let value = value.trim();
    let mut chars = value.chars();
    let truncated = chars.by_ref().take(MAX_CHARS).collect::<String>();
    if chars.next().is_some() {
        format!("{truncated}...")
    } else {
        truncated
    }
}

use super::*;

pub(super) fn execute_port_forward_list(
    port_forwards: &PortForwardService,
    storage: &RuntimeFileStore,
) -> ToolExecutionResult {
    match port_forwards.list(storage) {
        Ok(forwards) => ToolExecutionResult {
            status: McpToolExecutionStatus::Succeeded,
            result_summary: Some(summarize_port_forward_list_for_agent(&forwards)),
            error: None,
            ..ToolExecutionResult::default()
        },
        Err(error) => failure(error.to_string()),
    }
}

pub(super) fn execute_port_forward_close(
    port_forwards: &PortForwardService,
    local_network_proxy: &LocalNetworkProxyService,
    storage: &RuntimeFileStore,
    arguments: &serde_json::Map<String, Value>,
) -> ToolExecutionResult {
    let forward_id = match required_string_arg(arguments, "forwardId") {
        Ok(forward_id) => forward_id,
        Err(error) => return failure(error.to_string()),
    };

    let summary = match port_forwards.get(storage, &forward_id) {
        Ok(summary) => summary,
        Err(error) => return failure(error.to_string()),
    };
    match port_forwards.close(storage, &forward_id) {
        Ok(true) => {
            if let Some(entry_id) = summary.and_then(|summary| summary.local_proxy_entry_id) {
                let _ = local_network_proxy.release_entry(&entry_id);
            }
            ToolExecutionResult {
                status: McpToolExecutionStatus::Succeeded,
                result_summary: Some(format!("端口转发已停止并保留配置：{forward_id}。")),
                error: None,
                ..ToolExecutionResult::default()
            }
        }
        Ok(false) => failure(format!("端口转发不存在或已关闭：{forward_id}。")),
        Err(error) => failure(error.to_string()),
    }
}

pub(super) fn execute_port_forward_create(
    port_forwards: &PortForwardService,
    local_network_proxy: &LocalNetworkProxyService,
    storage: &RuntimeFileStore,
    remote_hosts: &RemoteHostService,
    paths: &KerminalPaths,
    arguments: &serde_json::Map<String, Value>,
) -> ToolExecutionResult {
    let request = match port_forward_create_request_from_arguments(arguments)
        .and_then(|request| prepare_agent_port_forward_request(local_network_proxy, request))
    {
        Ok(request) => request,
        Err(error) => return failure(error.to_string()),
    };
    let local_proxy_entry_id = request.local_proxy_entry_id.clone();

    match port_forwards.create_with_context(storage, remote_hosts, paths, request) {
        Ok(summary) => ToolExecutionResult {
            status: McpToolExecutionStatus::Succeeded,
            result_summary: Some(summarize_port_forward_for_agent(&summary)),
            error: None,
            ..ToolExecutionResult::default()
        },
        Err(error) => {
            if let Some(entry_id) = local_proxy_entry_id.as_deref() {
                let _ = local_network_proxy.release_entry(entry_id);
            }
            failure(error.to_string())
        }
    }
}

pub(super) fn port_forward_create_request_from_arguments(
    arguments: &serde_json::Map<String, Value>,
) -> AppResult<PortForwardCreateRequest> {
    Ok(PortForwardCreateRequest {
        host_id: required_string_arg(arguments, "hostId")?,
        name: optional_string_arg(arguments, "name")?,
        kind: required_port_forward_kind_arg(arguments)?,
        purpose: optional_port_forward_purpose_arg(arguments)?,
        origin: PortForwardOrigin::McpTool,
        bind_host: optional_string_arg(arguments, "bindHost")?,
        local_bind_host: optional_string_arg(arguments, "localBindHost")?,
        remote_bind_host: optional_string_arg(arguments, "remoteBindHost")?,
        source_port: required_port_arg(arguments, "sourcePort")?,
        target_host: optional_string_arg(arguments, "targetHost")?,
        target_port: optional_port_arg(arguments, "targetPort")?,
        local_endpoint: local_endpoint_arg(arguments)?,
        remote_endpoint: remote_endpoint_arg(arguments)?,
        proxy_protocol: optional_port_forward_proxy_protocol_arg(arguments)?,
        remote_access_scope: optional_remote_access_scope_arg(arguments)?,
        proxy_apply_scope: optional_proxy_apply_scope_arg(arguments)?,
        ..Default::default()
    })
}

fn prepare_agent_port_forward_request(
    local_network_proxy: &LocalNetworkProxyService,
    mut request: PortForwardCreateRequest,
) -> AppResult<PortForwardCreateRequest> {
    let protocol = request
        .proxy_protocol
        .unwrap_or(PortForwardProxyProtocol::Http);
    if request.purpose != PortForwardPurpose::HostNetworkAssist
        || protocol != PortForwardProxyProtocol::Http
    {
        return Ok(request);
    }
    if request.local_proxy_entry_id.is_some() && request.local_endpoint.is_some() {
        return Ok(request);
    }

    let local_bind_host = request.local_bind_host.clone().or_else(|| {
        request
            .local_endpoint
            .as_ref()
            .map(|endpoint| endpoint.host.clone())
    });
    let local_port = request
        .local_endpoint
        .as_ref()
        .and_then(|endpoint| endpoint.port);
    let entry = local_network_proxy.acquire_entry(LocalProxyEntryRequest {
        bind_host: local_bind_host,
        host_id: request.host_id.clone(),
        port: local_port,
        session_id: format!("network-assist-agent-{}", Uuid::new_v4()),
        tag: Some("network-assist/http/agent".to_owned()),
    })?;

    request.local_bind_host = Some(entry.bind_host.clone());
    request.local_endpoint = Some(PortForwardEndpoint {
        host: entry.bind_host,
        label: Some("本机 HTTP CONNECT 代理".to_owned()),
        port: Some(entry.port),
    });
    request.shared_proxy_service_id = Some(entry.service_id);
    request.local_proxy_entry_id = Some(entry.entry_id);
    request.proxy_protocol = Some(PortForwardProxyProtocol::Http);
    Ok(request)
}

pub(super) fn required_port_forward_kind_arg(
    arguments: &serde_json::Map<String, Value>,
) -> AppResult<PortForwardKind> {
    match arguments.get("kind") {
        Some(Value::String(value)) => match value.as_str() {
            "local" => Ok(PortForwardKind::Local),
            "remote" => Ok(PortForwardKind::Remote),
            "dynamic" => Ok(PortForwardKind::Dynamic),
            _ => Err(AppError::InvalidInput(
                "kind 只支持 local、remote 或 dynamic。".to_owned(),
            )),
        },
        Some(Value::Null) | None => Err(AppError::InvalidInput("kind 不能为空。".to_owned())),
        _ => Err(AppError::InvalidInput("kind 必须是字符串。".to_owned())),
    }
}

fn optional_port_forward_purpose_arg(
    arguments: &serde_json::Map<String, Value>,
) -> AppResult<PortForwardPurpose> {
    match arguments.get("purpose") {
        Some(Value::String(value)) => match value.as_str() {
            "generic" => Ok(PortForwardPurpose::Generic),
            "hostNetworkAssist" => Ok(PortForwardPurpose::HostNetworkAssist),
            _ => Err(AppError::InvalidInput(
                "purpose 只支持 generic 或 hostNetworkAssist。".to_owned(),
            )),
        },
        Some(Value::Null) | None => Ok(PortForwardPurpose::Generic),
        _ => Err(AppError::InvalidInput("purpose 必须是字符串。".to_owned())),
    }
}

fn optional_port_forward_proxy_protocol_arg(
    arguments: &serde_json::Map<String, Value>,
) -> AppResult<Option<PortForwardProxyProtocol>> {
    match arguments.get("proxyProtocol") {
        Some(Value::String(value)) => match value.as_str() {
            "http" => Ok(Some(PortForwardProxyProtocol::Http)),
            "socks5" => Ok(Some(PortForwardProxyProtocol::Socks5)),
            _ => Err(AppError::InvalidInput(
                "proxyProtocol 只支持 http 或 socks5。".to_owned(),
            )),
        },
        Some(Value::Null) | None => Ok(None),
        _ => Err(AppError::InvalidInput(
            "proxyProtocol 必须是字符串。".to_owned(),
        )),
    }
}

fn optional_remote_access_scope_arg(
    arguments: &serde_json::Map<String, Value>,
) -> AppResult<Option<PortForwardRemoteAccessScope>> {
    match arguments.get("remoteAccessScope") {
        Some(Value::String(value)) => match value.as_str() {
            "loopback" => Ok(Some(PortForwardRemoteAccessScope::Loopback)),
            "privateNetwork" => Ok(Some(PortForwardRemoteAccessScope::PrivateNetwork)),
            "allInterfaces" => Ok(Some(PortForwardRemoteAccessScope::AllInterfaces)),
            "custom" => Ok(Some(PortForwardRemoteAccessScope::Custom)),
            _ => Err(AppError::InvalidInput(
                "remoteAccessScope 只支持 loopback、privateNetwork、allInterfaces 或 custom。"
                    .to_owned(),
            )),
        },
        Some(Value::Null) | None => Ok(None),
        _ => Err(AppError::InvalidInput(
            "remoteAccessScope 必须是字符串。".to_owned(),
        )),
    }
}

fn optional_proxy_apply_scope_arg(
    arguments: &serde_json::Map<String, Value>,
) -> AppResult<PortForwardProxyApplyScope> {
    match arguments.get("proxyApplyScope") {
        Some(Value::String(value)) => match value.as_str() {
            "none" => Ok(PortForwardProxyApplyScope::None),
            "currentTerminal" => Ok(PortForwardProxyApplyScope::CurrentTerminal),
            "futureTerminals" => Ok(PortForwardProxyApplyScope::FutureTerminals),
            "userProfile" => Ok(PortForwardProxyApplyScope::UserProfile),
            "toolOnly" => Ok(PortForwardProxyApplyScope::ToolOnly),
            _ => Err(AppError::InvalidInput(
                "proxyApplyScope 只支持 none、currentTerminal、futureTerminals、userProfile 或 toolOnly。"
                    .to_owned(),
            )),
        },
        Some(Value::Null) | None => Ok(PortForwardProxyApplyScope::None),
        _ => Err(AppError::InvalidInput(
            "proxyApplyScope 必须是字符串。".to_owned(),
        )),
    }
}

fn local_endpoint_arg(
    arguments: &serde_json::Map<String, Value>,
) -> AppResult<Option<PortForwardEndpoint>> {
    endpoint_arg(
        optional_string_arg(arguments, "localProxyHost")?,
        optional_zero_or_port_arg(arguments, "localProxyPort")?,
        "本机 HTTP CONNECT 代理",
    )
}

fn remote_endpoint_arg(
    arguments: &serde_json::Map<String, Value>,
) -> AppResult<Option<PortForwardEndpoint>> {
    endpoint_arg(
        optional_string_arg(arguments, "remoteProxyHost")?,
        optional_port_arg(arguments, "remoteProxyPort")?,
        "主机代理监听",
    )
}

fn optional_zero_or_port_arg(
    arguments: &serde_json::Map<String, Value>,
    key: &str,
) -> AppResult<Option<u16>> {
    match arguments.get(key) {
        Some(Value::Number(value)) => value
            .as_u64()
            .and_then(|value| u16::try_from(value).ok())
            .map(Some)
            .ok_or_else(|| AppError::InvalidInput(format!("{key} 必须是 0 到 65535 的数字。"))),
        Some(Value::Null) | None => Ok(None),
        _ => Err(AppError::InvalidInput(format!("{key} 必须是数字。"))),
    }
}

fn endpoint_arg(
    host: Option<String>,
    port: Option<u16>,
    label: &str,
) -> AppResult<Option<PortForwardEndpoint>> {
    match (host, port) {
        (None, None) => Ok(None),
        (Some(host), Some(port)) => Ok(Some(PortForwardEndpoint {
            host,
            label: Some(label.to_owned()),
            port: Some(port),
        })),
        (Some(_), None) => Err(AppError::InvalidInput(format!("{label}端口不能为空。"))),
        (None, Some(_)) => Err(AppError::InvalidInput(format!("{label}地址不能为空。"))),
    }
}

pub(super) fn required_port_arg(
    arguments: &serde_json::Map<String, Value>,
    key: &str,
) -> AppResult<u16> {
    match arguments.get(key) {
        Some(Value::Number(value)) => value
            .as_u64()
            .and_then(|value| u16::try_from(value).ok())
            .filter(|value| *value > 0)
            .ok_or_else(|| AppError::InvalidInput(format!("{key} 必须是 1 到 65535 的数字。"))),
        Some(Value::Null) | None => Err(AppError::InvalidInput(format!("{key} 不能为空。"))),
        _ => Err(AppError::InvalidInput(format!("{key} 必须是数字。"))),
    }
}

pub(super) fn optional_port_arg(
    arguments: &serde_json::Map<String, Value>,
    key: &str,
) -> AppResult<Option<u16>> {
    match arguments.get(key) {
        Some(Value::Number(value)) => value
            .as_u64()
            .and_then(|value| u16::try_from(value).ok())
            .filter(|value| *value > 0)
            .map(Some)
            .ok_or_else(|| AppError::InvalidInput(format!("{key} 必须是 1 到 65535 的数字。"))),
        Some(Value::Null) | None => Ok(None),
        _ => Err(AppError::InvalidInput(format!("{key} 必须是数字。"))),
    }
}

pub(super) fn summarize_port_forward_for_agent(summary: &PortForwardSummary) -> String {
    if summary.purpose == PortForwardPurpose::HostNetworkAssist {
        let proxy_url = summary.proxy_url.as_deref().unwrap_or("-");
        return format!(
            "主机网络助手已创建：“{}”，代理地址 {}，主机：{}，应用范围：{}。",
            summary.name,
            proxy_url,
            summary.host_name,
            proxy_apply_scope_label(summary.proxy_apply_scope)
        );
    }

    let endpoint = format!("{}:{}", summary.bind_host, summary.source_port);
    let kind = port_forward_kind_label(summary.kind);
    let route = match summary.kind {
        PortForwardKind::Dynamic => endpoint,
        PortForwardKind::Local | PortForwardKind::Remote => {
            let target_host = summary.target_host.as_deref().unwrap_or("-");
            let target_port = summary
                .target_port
                .map(|port| port.to_string())
                .unwrap_or_else(|| "-".to_owned());
            format!("{endpoint} -> {target_host}:{target_port}")
        }
    };

    format!(
        "端口转发已创建：“{}”，{} {}，主机：{}。",
        summary.name, kind, route, summary.host_name
    )
}

pub(super) fn summarize_port_forward_list_for_agent(forwards: &[PortForwardSummary]) -> String {
    if forwards.is_empty() {
        return "当前没有端口转发会话。".to_owned();
    }

    let running_count = forwards
        .iter()
        .filter(|summary| summary.status == PortForwardStatus::Running)
        .count();
    let exited_count = forwards.len().saturating_sub(running_count);
    let samples = forwards
        .iter()
        .take(5)
        .map(port_forward_sample_for_agent)
        .collect::<Vec<_>>()
        .join("；");

    format!(
        "当前共有 {} 个端口转发会话，运行中 {}，已退出 {}。示例：{}。",
        forwards.len(),
        running_count,
        exited_count,
        samples
    )
}

pub(super) fn port_forward_sample_for_agent(summary: &PortForwardSummary) -> String {
    let status = match summary.status {
        PortForwardStatus::Running => "运行中",
        PortForwardStatus::Exited => "已退出",
    };
    if summary.purpose == PortForwardPurpose::HostNetworkAssist {
        return format!(
            "{}（主机网络助手，代理={}，{}，应用范围={}，id={}）",
            summary.name,
            summary.proxy_url.as_deref().unwrap_or("-"),
            status,
            proxy_apply_scope_label(summary.proxy_apply_scope),
            summary.id
        );
    }

    let endpoint = format!("{}:{}", summary.bind_host, summary.source_port);
    let route = match summary.kind {
        PortForwardKind::Dynamic => endpoint,
        PortForwardKind::Local | PortForwardKind::Remote => {
            let target_host = summary.target_host.as_deref().unwrap_or("-");
            let target_port = summary
                .target_port
                .map(|port| port.to_string())
                .unwrap_or_else(|| "-".to_owned());
            format!("{endpoint} -> {target_host}:{target_port}")
        }
    };
    format!(
        "{}（{}，{}，{}，id={}）",
        summary.name,
        port_forward_kind_label(summary.kind),
        route,
        status,
        summary.id
    )
}

fn proxy_apply_scope_label(scope: PortForwardProxyApplyScope) -> &'static str {
    match scope {
        PortForwardProxyApplyScope::None => "仅创建隧道",
        PortForwardProxyApplyScope::CurrentTerminal => "当前终端",
        PortForwardProxyApplyScope::FutureTerminals => "后续终端",
        PortForwardProxyApplyScope::UserProfile => "用户级配置",
        PortForwardProxyApplyScope::ToolOnly => "外部 Agent/工具命令",
    }
}

pub(super) fn port_forward_kind_label(kind: PortForwardKind) -> &'static str {
    match kind {
        PortForwardKind::Local => "local",
        PortForwardKind::Remote => "remote",
        PortForwardKind::Dynamic => "dynamic",
    }
}

use super::*;

#[allow(clippy::result_large_err)]
fn resolve_ssh_target_host(
    remote_hosts: &RemoteHostService,
    arguments: &serde_json::Map<String, Value>,
) -> Result<RemoteHost, ToolExecutionResult> {
    let tree = remote_hosts
        .list_tree()
        .map_err(|error| failure(error.to_string()))?;
    let hosts = tree
        .iter()
        .flat_map(|group| {
            group
                .hosts
                .iter()
                .map(|host| (group.id.as_str(), group.name.as_str(), host))
        })
        .collect::<Vec<_>>();
    let selector =
        SshTargetSelector::from_arguments(arguments).map_err(|error| ToolExecutionResult {
            status: McpToolExecutionStatus::Failed,
            error: Some(error.to_string()),
            error_kind: Some("missingTarget".to_owned()),
            recoverable: true,
            next_hints: vec![
                "提供 hostId，或提供 groupName/name/host/username/port 组合后重试。".to_owned(),
            ],
            ..ToolExecutionResult::default()
        })?;

    if let Some(host_id) = selector.host_id.as_deref() {
        return hosts
            .iter()
            .find(|(_, _, host)| host.id == host_id)
            .map(|(_, _, host)| (*host).clone())
            .ok_or_else(|| target_not_found_result(&format!("远程主机不存在: {host_id}"), &hosts));
    }

    let matches = hosts
        .iter()
        .filter(|(group_id, group_name, host)| selector.matches(group_id, group_name, host))
        .map(|(_, _, host)| (*host).clone())
        .collect::<Vec<_>>();

    match matches.as_slice() {
        [host] => Ok(host.clone()),
        [] => Err(target_not_found_result("未找到匹配的 SSH 主机。", &hosts)),
        _ => Err(ambiguous_target_result(&matches)),
    }
}

#[derive(Debug)]
struct SshTargetSelector {
    host_id: Option<String>,
    group_id: Option<String>,
    group_name: Option<String>,
    name: Option<String>,
    host: Option<String>,
    username: Option<String>,
    port: Option<u16>,
}

impl SshTargetSelector {
    fn from_arguments(arguments: &serde_json::Map<String, Value>) -> AppResult<Self> {
        let selector = Self {
            host_id: trimmed_optional_string_arg(arguments, "hostId")?,
            group_id: trimmed_optional_string_arg(arguments, "groupId")?,
            group_name: trimmed_optional_string_arg(arguments, "groupName")?,
            name: trimmed_optional_string_arg(arguments, "name")?,
            host: trimmed_optional_string_arg(arguments, "host")?,
            username: trimmed_optional_string_arg(arguments, "username")?,
            port: number_to_u16(arguments.get("port")),
        };
        if selector.host_id.is_none()
            && selector.group_id.is_none()
            && selector.group_name.is_none()
            && selector.name.is_none()
            && selector.host.is_none()
            && selector.username.is_none()
            && selector.port.is_none()
        {
            return Err(AppError::InvalidInput(
                "SSH 目标需要 hostId，或至少一个主机选择条件。".to_owned(),
            ));
        }
        Ok(selector)
    }

    fn matches(&self, group_id: &str, group_name: &str, host: &RemoteHost) -> bool {
        self.group_id
            .as_deref()
            .is_none_or(|expected| group_id == expected)
            && self
                .group_name
                .as_deref()
                .is_none_or(|expected| group_name.eq_ignore_ascii_case(expected))
            && self
                .name
                .as_deref()
                .is_none_or(|expected| host.name.eq_ignore_ascii_case(expected))
            && self
                .host
                .as_deref()
                .is_none_or(|expected| host.host.eq_ignore_ascii_case(expected))
            && self
                .username
                .as_deref()
                .is_none_or(|expected| host.username.eq_ignore_ascii_case(expected))
            && self.port.is_none_or(|expected| host.port == expected)
    }
}

fn trimmed_optional_string_arg(
    arguments: &serde_json::Map<String, Value>,
    key: &str,
) -> AppResult<Option<String>> {
    Ok(optional_string_arg(arguments, key)?
        .map(|value| value.trim().to_owned())
        .filter(|value| !value.is_empty()))
}

fn target_not_found_result(
    message: &str,
    hosts: &[(&str, &str, &RemoteHost)],
) -> ToolExecutionResult {
    ToolExecutionResult {
        status: McpToolExecutionStatus::Failed,
        error: Some(message.to_owned()),
        structured_result: Some(json!({
            "candidateCount": hosts.len(),
            "candidates": hosts
                .iter()
                .take(10)
                .map(|(group_id, group_name, host)| ssh_target_candidate(group_id, group_name, host))
                .collect::<Vec<_>>(),
        })),
        entities: hosts
            .iter()
            .take(10)
            .map(|(group_id, group_name, host)| ssh_target_entity(group_id, group_name, host))
            .collect(),
        error_kind: Some("targetNotFound".to_owned()),
        recoverable: true,
        next_hints: vec![
            "检查 hosts/*.toml 中的主机配置，或在调用参数里提供更明确的 hostId。".to_owned(),
        ],
        ..ToolExecutionResult::default()
    }
}

fn ambiguous_target_result(matches: &[RemoteHost]) -> ToolExecutionResult {
    ToolExecutionResult {
        status: McpToolExecutionStatus::Failed,
        error: Some(format!(
            "匹配到 {} 个 SSH 主机，请补充 hostId。",
            matches.len()
        )),
        structured_result: Some(json!({
            "candidateCount": matches.len(),
            "candidates": matches
                .iter()
                .take(10)
                .map(|host| {
                    json!({
                        "hostId": host.id,
                        "groupId": host.group_id,
                        "name": host.name,
                        "host": host.host,
                        "port": host.port,
                        "username": host.username,
                        "production": host.production,
                    })
                })
                .collect::<Vec<_>>(),
        })),
        entities: matches
            .iter()
            .take(10)
            .map(|host| {
                json!({
                    "type": "remoteHost",
                    "id": host.id,
                    "groupId": host.group_id,
                    "name": host.name,
                    "host": host.host,
                    "port": host.port,
                    "username": host.username,
                    "production": host.production,
                })
            })
            .collect(),
        error_kind: Some("ambiguousTarget".to_owned()),
        recoverable: true,
        next_hints: vec!["从 candidates 中选择一个 hostId 后重试。".to_owned()],
        ..ToolExecutionResult::default()
    }
}

fn ssh_target_candidate(group_id: &str, group_name: &str, host: &RemoteHost) -> Value {
    json!({
        "hostId": host.id,
        "groupId": group_id,
        "groupName": group_name,
        "name": host.name,
        "host": host.host,
        "port": host.port,
        "username": host.username,
        "production": host.production,
    })
}

fn ssh_target_entity(group_id: &str, group_name: &str, host: &RemoteHost) -> Value {
    json!({
        "type": "remoteHost",
        "id": host.id,
        "groupId": group_id,
        "groupName": group_name,
        "name": host.name,
        "host": host.host,
        "port": host.port,
        "username": host.username,
        "production": host.production,
    })
}

pub(super) async fn execute_ssh_command(
    ssh_commands: &SshCommandService,
    command_history: &CommandHistoryService,
    paths: &KerminalPaths,
    command_store: &CommandSqliteStore,
    arguments: &serde_json::Map<String, Value>,
) -> ToolExecutionResult {
    let request = match ssh_command_request_from_arguments(arguments) {
        Ok(request) => request,
        Err(error) => return failure(error.to_string()),
    };
    execute_ssh_command_request(
        ssh_commands,
        command_history,
        paths,
        command_store,
        request,
        None,
    )
    .await
}

pub(super) async fn execute_ssh_command_on_resolved_host(
    ssh_commands: &SshCommandService,
    command_history: &CommandHistoryService,
    paths: &KerminalPaths,
    remote_hosts: &RemoteHostService,
    command_store: &CommandSqliteStore,
    arguments: &serde_json::Map<String, Value>,
) -> ToolExecutionResult {
    let host = match resolve_ssh_target_host(remote_hosts, arguments) {
        Ok(host) => host,
        Err(result) => return result,
    };
    let request = match ssh_command_request_from_arguments_with_host_id(arguments, host.id.clone())
    {
        Ok(request) => request,
        Err(error) => return failure(error.to_string()),
    };
    execute_ssh_command_request(
        ssh_commands,
        command_history,
        paths,
        command_store,
        request,
        Some(&host),
    )
    .await
}

async fn execute_ssh_command_request(
    ssh_commands: &SshCommandService,
    command_history: &CommandHistoryService,
    paths: &KerminalPaths,
    command_store: &CommandSqliteStore,
    request: SshCommandRequest,
    resolved_host: Option<&RemoteHost>,
) -> ToolExecutionResult {
    let history_request = CommandHistoryRecordRequest {
        command: request.command.clone(),
        source: CommandHistorySource::Tool,
        target: CommandHistoryTarget::Ssh,
        record: None,
        session_id: None,
        pane_id: None,
        tab_id: None,
        profile_id: None,
        remote_host_id: Some(request.host_id.clone()),
        cwd: None,
        shell: Some("ssh".to_owned()),
    };

    match ssh_commands.execute_native(paths, request).await {
        Ok(output) if output.success => {
            let _ = command_history.record_command(command_store, history_request);
            ToolExecutionResult {
                status: McpToolExecutionStatus::Succeeded,
                result_summary: Some(summarize_ssh_command_output_for_agent(&output)),
                error: None,
                structured_result: Some(ssh_command_structured_result(&output, resolved_host)),
                entities: ssh_command_entities(&output, resolved_host),
                ..ToolExecutionResult::default()
            }
        }
        Ok(output) => {
            let exit_code = output
                .exit_code
                .map(|code| code.to_string())
                .unwrap_or_else(|| "未知".to_owned());
            ToolExecutionResult {
                status: McpToolExecutionStatus::Failed,
                result_summary: Some(summarize_ssh_command_output_for_agent(&output)),
                error: Some(format!("远程命令退出码 {exit_code}")),
                structured_result: Some(ssh_command_structured_result(&output, resolved_host)),
                entities: ssh_command_entities(&output, resolved_host),
                error_kind: Some("remoteCommandFailed".to_owned()),
                recoverable: true,
                next_hints: vec!["检查远程命令、权限和工作目录后重试。".to_owned()],
            }
        }
        Err(error) => ToolExecutionResult {
            status: McpToolExecutionStatus::Failed,
            error: Some(error.to_string()),
            entities: resolved_host
                .map(|host| vec![ssh_host_entity(host)])
                .unwrap_or_default(),
            error_kind: Some("remoteFailure".to_owned()),
            recoverable: true,
            next_hints: vec!["检查 SSH 主机、凭据、网络和主机密钥信任状态后重试。".to_owned()],
            ..ToolExecutionResult::default()
        },
    }
}

pub(super) fn ssh_command_request_from_arguments(
    arguments: &serde_json::Map<String, Value>,
) -> AppResult<SshCommandRequest> {
    ssh_command_request_from_arguments_with_host_id(
        arguments,
        required_string_arg(arguments, "hostId")?,
    )
}

fn ssh_command_request_from_arguments_with_host_id(
    arguments: &serde_json::Map<String, Value>,
    host_id: String,
) -> AppResult<SshCommandRequest> {
    let command = required_string_arg(arguments, "command")?;
    Ok(SshCommandRequest {
        host_id,
        command: wrap_command_with_proxy_env(
            command,
            optional_string_arg(arguments, "proxyUrl")?,
            optional_string_arg(arguments, "proxyProtocol")?,
        )?,
        timeout_seconds: optional_u64_arg(arguments, "timeoutSeconds")?,
        max_output_bytes: optional_usize_arg(arguments, "maxOutputBytes")?,
    })
}

fn ssh_command_structured_result(
    output: &SshCommandOutput,
    resolved_host: Option<&RemoteHost>,
) -> Value {
    json!({
        "hostId": output.host_id,
        "groupId": resolved_host.and_then(|host| host.group_id.clone()),
        "host": resolved_host
            .map(ssh_host_details)
            .unwrap_or_else(|| json!({
                "id": output.host_id,
                "name": output.host_name,
                "host": output.host,
                "port": output.port,
                "username": output.username,
            })),
        "command": {
            "maxOutputBytes": output.max_output_bytes,
        },
        "output": {
            "success": output.success,
            "exitCode": output.exit_code,
            "stdout": output.stdout,
            "stderr": output.stderr,
            "stdoutBytes": output.stdout_bytes,
            "stderrBytes": output.stderr_bytes,
            "stdoutTruncated": output.stdout_truncated,
            "stderrTruncated": output.stderr_truncated,
            "durationMs": output.duration_ms,
        },
    })
}

fn ssh_command_entities(
    output: &SshCommandOutput,
    resolved_host: Option<&RemoteHost>,
) -> Vec<Value> {
    match resolved_host {
        Some(host) => vec![ssh_host_entity(host)],
        None => vec![json!({
            "type": "remoteHost",
            "id": output.host_id,
            "name": output.host_name,
            "host": output.host,
            "port": output.port,
            "username": output.username,
        })],
    }
}

fn ssh_host_details(host: &RemoteHost) -> Value {
    json!({
        "id": host.id,
        "groupId": host.group_id,
        "name": host.name,
        "host": host.host,
        "port": host.port,
        "username": host.username,
        "production": host.production,
    })
}

fn ssh_host_entity(host: &RemoteHost) -> Value {
    json!({
        "type": "remoteHost",
        "id": host.id,
        "groupId": host.group_id,
        "name": host.name,
        "host": host.host,
        "port": host.port,
        "username": host.username,
        "production": host.production,
    })
}

fn wrap_command_with_proxy_env(
    command: String,
    proxy_url: Option<String>,
    proxy_protocol: Option<String>,
) -> AppResult<String> {
    let Some(proxy_url) = proxy_url else {
        return Ok(command);
    };
    validate_proxy_url(&proxy_url)?;
    let protocol = proxy_protocol.unwrap_or_else(|| {
        if proxy_url.starts_with("socks5h://") {
            "socks5".to_owned()
        } else {
            "http".to_owned()
        }
    });
    let quoted_proxy = shell_quote(&proxy_url);
    let quoted_no_proxy = shell_quote("localhost,127.0.0.1");
    let exports = match protocol.as_str() {
        "http" => vec![
            format!("export HTTP_PROXY={quoted_proxy}"),
            format!("export HTTPS_PROXY={quoted_proxy}"),
            format!("export http_proxy={quoted_proxy}"),
            format!("export https_proxy={quoted_proxy}"),
            format!("export NO_PROXY={quoted_no_proxy}"),
            format!("export no_proxy={quoted_no_proxy}"),
        ],
        "socks5" => vec![
            format!("export ALL_PROXY={quoted_proxy}"),
            format!("export all_proxy={quoted_proxy}"),
            format!("export NO_PROXY={quoted_no_proxy}"),
            format!("export no_proxy={quoted_no_proxy}"),
        ],
        _ => {
            return Err(AppError::InvalidInput(
                "proxyProtocol 只支持 http 或 socks5。".to_owned(),
            ));
        }
    };

    Ok(format!("{}\n{}", exports.join("\n"), command))
}

fn validate_proxy_url(proxy_url: &str) -> AppResult<()> {
    if proxy_url.contains('\0') || proxy_url.contains('\n') || proxy_url.contains('\r') {
        return Err(AppError::InvalidInput(
            "proxyUrl 不能包含控制字符。".to_owned(),
        ));
    }
    if proxy_url.starts_with("http://")
        || proxy_url.starts_with("https://")
        || proxy_url.starts_with("socks5h://")
    {
        return Ok(());
    }
    Err(AppError::InvalidInput(
        "proxyUrl 只支持 http://、https:// 或 socks5h://。".to_owned(),
    ))
}

fn shell_quote(value: &str) -> String {
    format!("'{}'", value.replace('\'', "'\\''"))
}

/// 将远程命令执行输出压缩成外部 Agent 可读摘要，避免返回完整 stdout/stderr。
pub fn summarize_ssh_command_output_for_agent(output: &SshCommandOutput) -> String {
    let exit_code = output
        .exit_code
        .map(|code| code.to_string())
        .unwrap_or_else(|| "未知".to_owned());
    let stdout = output_stream_summary(
        "stdout",
        &output.stdout,
        output.stdout_bytes,
        output.stdout_truncated,
    );
    let stderr = output_stream_summary(
        "stderr",
        &output.stderr,
        output.stderr_bytes,
        output.stderr_truncated,
    );

    format!(
        "远程命令已执行：{}（{}@{}:{}），退出码：{}，{}，{}，耗时：{} ms。",
        output.host_name,
        output.username,
        output.host,
        output.port,
        exit_code,
        stdout,
        stderr,
        output.duration_ms
    )
}

pub(super) fn output_stream_summary(
    label: &str,
    text: &str,
    bytes: usize,
    truncated: bool,
) -> String {
    let sample = text.lines().take(4).collect::<Vec<_>>().join(" ");
    let sample = collapse_whitespace(&sample);
    let sample = truncate_string(&sample);
    let (sample, redacted) = redact_terminal_text(&sample);
    let truncation_label = if truncated { "，已截断" } else { "" };
    let redaction_label = if redacted { "，已脱敏" } else { "" };

    if sample.is_empty() {
        format!("{label}：{bytes} 字节{truncation_label}{redaction_label}")
    } else {
        format!("{label}：{bytes} 字节{truncation_label}{redaction_label}，片段：{sample}")
    }
}

//! SSH 端口转发命令计划模型。
//!
//! @author kongweiguang

use std::{fmt, net::IpAddr, path::PathBuf};

use crate::{
    error::{AppError, AppResult},
    models::{
        port_forward::{
            PortForwardCreateRequest, PortForwardEndpoint, PortForwardKind,
            PortForwardProxyProtocol, PortForwardPurpose, PortForwardRemoteAccessScope,
            PortForwardStatus, PortForwardSummary,
        },
        remote_host::RemoteHost,
        terminal::TerminalSecretInputPlan,
    },
    paths::KerminalPaths,
    services::{
        ssh_command_plan::{
            known_hosts_args, preferred_authentication_args, resolve_ssh_auth_plan, SshAuthMethod,
        },
        ssh_route_plan::{build_ssh_route_plan, materialize_openssh_route_plan},
    },
};

/// OpenSSH 端口转发命令的完整运行时计划。
#[derive(Clone, PartialEq, Eq)]
pub struct ForwardCommandPlan {
    /// OpenSSH 可执行文件路径或命令名。
    pub executable: String,
    /// 传给 OpenSSH 的参数，不包含密码或内联私钥明文。
    pub args: Vec<String>,
    /// 端口转发进程结束后需要清理的临时文件。
    pub cleanup_paths: Vec<PathBuf>,
    /// 密码认证时的 PTY 安全输入计划。
    pub secret_input_plan: Option<TerminalSecretInputPlan>,
    /// 实际监听地址。
    pub bind_host: String,
    /// 目标主机；动态 SOCKS 转发可为空。
    pub target_host: Option<String>,
    /// 目标端口；动态 SOCKS 转发可为空。
    pub target_port: Option<u16>,
    /// 本机监听地址或本机侧代理入口地址。
    pub local_bind_host: Option<String>,
    /// 远端监听地址。
    pub remote_bind_host: Option<String>,
    /// 本机侧端点。
    pub local_endpoint: Option<PortForwardEndpoint>,
    /// 远端侧端点。
    pub remote_endpoint: Option<PortForwardEndpoint>,
    /// 主机网络助手代理协议。
    pub proxy_protocol: Option<PortForwardProxyProtocol>,
    /// 远端监听可见范围。
    pub remote_access_scope: Option<PortForwardRemoteAccessScope>,
    /// 用户可复制的代理 URL。
    pub proxy_url: Option<String>,
    /// 脱敏后的命令预览。
    pub command_preview: String,
}

impl fmt::Debug for ForwardCommandPlan {
    fn fmt(&self, formatter: &mut fmt::Formatter<'_>) -> fmt::Result {
        formatter
            .debug_struct("ForwardCommandPlan")
            .field("executable", &self.executable)
            .field("args", &self.args)
            .field("cleanup_paths", &self.cleanup_paths)
            .field(
                "secret_entry_count",
                &self
                    .secret_input_plan
                    .as_ref()
                    .map(|plan| plan.entries.len())
                    .unwrap_or_default(),
            )
            .field("bind_host", &self.bind_host)
            .field("target_host", &self.target_host)
            .field("target_port", &self.target_port)
            .field("local_bind_host", &self.local_bind_host)
            .field("remote_bind_host", &self.remote_bind_host)
            .field("local_endpoint", &self.local_endpoint)
            .field("remote_endpoint", &self.remote_endpoint)
            .field("proxy_protocol", &self.proxy_protocol)
            .field("remote_access_scope", &self.remote_access_scope)
            .field("proxy_url", &self.proxy_url)
            .field("command_preview", &self.command_preview)
            .finish()
    }
}

impl ForwardCommandPlan {
    pub(super) fn to_summary(
        &self,
        host: &RemoteHost,
        request: &PortForwardCreateRequest,
        pid: Option<u32>,
        id: String,
        created_at: String,
    ) -> PortForwardSummary {
        PortForwardSummary {
            id,
            host_id: host.id.clone(),
            host_name: host.name.clone(),
            name: normalized_name(request, host),
            kind: request.kind,
            purpose: request.purpose,
            origin: request.origin,
            bind_host: self.bind_host.clone(),
            local_bind_host: self.local_bind_host.clone(),
            remote_bind_host: self.remote_bind_host.clone(),
            source_port: request.source_port,
            target_host: self.target_host.clone(),
            target_port: self.target_port,
            local_endpoint: self.local_endpoint.clone(),
            remote_endpoint: self.remote_endpoint.clone(),
            proxy_protocol: self.proxy_protocol,
            remote_access_scope: self.remote_access_scope,
            proxy_url: self.proxy_url.clone(),
            proxy_apply_scope: request.proxy_apply_scope,
            shared_proxy_service_id: request.shared_proxy_service_id.clone(),
            local_proxy_entry_id: request.local_proxy_entry_id.clone(),
            command_preview: self.command_preview.clone(),
            last_error: None,
            pid,
            status: PortForwardStatus::Running,
            created_at,
        }
    }
}

/// 构建 OpenSSH 端口转发启动计划。
#[doc(hidden)]
pub fn build_forward_plan(
    host: &RemoteHost,
    executable: String,
    paths: Option<&KerminalPaths>,
    request: &PortForwardCreateRequest,
) -> AppResult<ForwardCommandPlan> {
    if request.source_port == 0 {
        return Err(AppError::InvalidInput("监听端口必须大于 0".to_owned()));
    }

    let route = resolve_forward_route(request)?;
    let mut args = vec!["-N".to_owned(), "-T".to_owned(), "-a".to_owned()];
    let cleanup_paths;
    let secret_input_plan;

    if host.ssh_options.jump_hosts.is_empty() {
        let auth = resolve_ssh_auth_plan(host, paths)?;
        let batch_mode = auth.method != SshAuthMethod::Password;

        args.extend(["-p".to_owned(), host.port.to_string()]);
        if let Some(paths) = paths {
            args.extend(known_hosts_args(paths.root.join("known_hosts")));
        }
        if batch_mode {
            args.extend(["-o".to_owned(), "BatchMode=yes".to_owned()]);
        }
        args.extend(preferred_authentication_args(host.auth_type));
        args.extend(auth.args);
        args.extend(forward_common_args());
        args.push(forward_flag(route.kind).to_owned());
        args.push(route.forward_arg);
        args.push(format!("{}@{}", host.username, host.host));

        cleanup_paths = auth.cleanup_paths;
        secret_input_plan = auth
            .secret_input_response
            .map(TerminalSecretInputPlan::from);
    } else {
        let paths = paths.ok_or_else(|| {
            AppError::InvalidInput(
                "SSH 跳板端口转发需要应用路径上下文以创建临时 ssh config".to_owned(),
            )
        })?;
        let ssh_route = build_ssh_route_plan(host)?;
        let open_ssh =
            materialize_openssh_route_plan(&ssh_route, paths, paths.root.join("known_hosts"))?;

        if open_ssh.secret_input_plan.entries.is_empty() {
            args.extend(["-o".to_owned(), "BatchMode=yes".to_owned()]);
        }
        args.extend(forward_common_args());
        args.push(forward_flag(route.kind).to_owned());
        args.push(route.forward_arg);
        args.extend(open_ssh.args);

        cleanup_paths = open_ssh.cleanup_paths;
        secret_input_plan =
            (!open_ssh.secret_input_plan.entries.is_empty()).then_some(open_ssh.secret_input_plan);
    }

    let command_preview = command_preview(&executable, &args);

    Ok(ForwardCommandPlan {
        executable,
        args,
        cleanup_paths,
        secret_input_plan,
        bind_host: route.bind_host,
        target_host: route.target_host,
        target_port: route.target_port,
        local_bind_host: route.local_bind_host,
        remote_bind_host: route.remote_bind_host,
        local_endpoint: route.local_endpoint,
        remote_endpoint: route.remote_endpoint,
        proxy_protocol: route.proxy_protocol,
        remote_access_scope: route.remote_access_scope,
        proxy_url: route.proxy_url,
        command_preview,
    })
}

fn forward_common_args() -> Vec<String> {
    vec![
        "-o".to_owned(),
        "ExitOnForwardFailure=yes".to_owned(),
        "-o".to_owned(),
        "ServerAliveInterval=30".to_owned(),
        "-o".to_owned(),
        "ServerAliveCountMax=3".to_owned(),
    ]
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct ForwardRoutePlan {
    kind: PortForwardKind,
    forward_arg: String,
    bind_host: String,
    target_host: Option<String>,
    target_port: Option<u16>,
    local_bind_host: Option<String>,
    remote_bind_host: Option<String>,
    local_endpoint: Option<PortForwardEndpoint>,
    remote_endpoint: Option<PortForwardEndpoint>,
    proxy_protocol: Option<PortForwardProxyProtocol>,
    remote_access_scope: Option<PortForwardRemoteAccessScope>,
    proxy_url: Option<String>,
}

fn resolve_forward_route(request: &PortForwardCreateRequest) -> AppResult<ForwardRoutePlan> {
    if request.purpose == PortForwardPurpose::HostNetworkAssist {
        return resolve_host_network_assist_route(request);
    }

    match request.kind {
        PortForwardKind::Local => resolve_local_route(request),
        PortForwardKind::Remote => resolve_remote_route(request),
        PortForwardKind::Dynamic => resolve_dynamic_route(request),
    }
}

fn resolve_local_route(request: &PortForwardCreateRequest) -> AppResult<ForwardRoutePlan> {
    let bind_host = listener_bind_host(request.local_bind_host.as_deref(), request)?;
    let target_host = required_target_host(request)?;
    let target_port = required_target_port(request)?;
    let local_endpoint = endpoint(
        Some(bind_host.clone()),
        Some(request.source_port),
        "本机监听",
    )?;
    let remote_endpoint = endpoint(Some(target_host.clone()), Some(target_port), "主机目标服务")?;

    Ok(ForwardRoutePlan {
        kind: PortForwardKind::Local,
        forward_arg: format!(
            "{}:{}:{}:{}",
            bind_host, request.source_port, target_host, target_port
        ),
        bind_host,
        target_host: Some(target_host),
        target_port: Some(target_port),
        local_bind_host: local_endpoint
            .as_ref()
            .map(|endpoint| endpoint.host.clone()),
        remote_bind_host: None,
        local_endpoint,
        remote_endpoint,
        proxy_protocol: None,
        remote_access_scope: None,
        proxy_url: None,
    })
}

fn resolve_remote_route(request: &PortForwardCreateRequest) -> AppResult<ForwardRoutePlan> {
    let bind_host = listener_bind_host(request.remote_bind_host.as_deref(), request)?;
    let target_host = required_target_host(request)?;
    let target_port = required_target_port(request)?;
    let remote_endpoint = endpoint(
        Some(bind_host.clone()),
        Some(request.source_port),
        "主机监听",
    )?;
    let local_endpoint = endpoint(Some(target_host.clone()), Some(target_port), "本机目标服务")?;
    let remote_access_scope = Some(
        request
            .remote_access_scope
            .unwrap_or_else(|| infer_remote_access_scope(&bind_host)),
    );

    Ok(ForwardRoutePlan {
        kind: PortForwardKind::Remote,
        forward_arg: format!(
            "{}:{}:{}:{}",
            bind_host, request.source_port, target_host, target_port
        ),
        bind_host,
        target_host: Some(target_host),
        target_port: Some(target_port),
        local_bind_host: None,
        remote_bind_host: remote_endpoint
            .as_ref()
            .map(|endpoint| endpoint.host.clone()),
        local_endpoint,
        remote_endpoint,
        proxy_protocol: None,
        remote_access_scope,
        proxy_url: None,
    })
}

fn resolve_dynamic_route(request: &PortForwardCreateRequest) -> AppResult<ForwardRoutePlan> {
    let bind_host = listener_bind_host(request.local_bind_host.as_deref(), request)?;
    let local_endpoint = endpoint(
        Some(bind_host.clone()),
        Some(request.source_port),
        "本机 SOCKS",
    )?;

    Ok(ForwardRoutePlan {
        kind: PortForwardKind::Dynamic,
        forward_arg: format!("{}:{}", bind_host, request.source_port),
        bind_host,
        target_host: None,
        target_port: None,
        local_bind_host: local_endpoint
            .as_ref()
            .map(|endpoint| endpoint.host.clone()),
        remote_bind_host: None,
        local_endpoint,
        remote_endpoint: None,
        proxy_protocol: Some(PortForwardProxyProtocol::Socks5),
        remote_access_scope: None,
        proxy_url: Some(format!(
            "socks5h://{}:{}",
            format_proxy_host(&proxy_client_host(&request_bind_host(request))),
            request.source_port
        )),
    })
}

fn resolve_host_network_assist_route(
    request: &PortForwardCreateRequest,
) -> AppResult<ForwardRoutePlan> {
    let proxy_protocol = request
        .proxy_protocol
        .unwrap_or(PortForwardProxyProtocol::Http);
    let bind_host = listener_bind_host(request.remote_bind_host.as_deref(), request)?;
    let remote_endpoint = endpoint(
        Some(bind_host.clone()),
        Some(request.source_port),
        "主机代理监听",
    )?;
    let remote_access_scope = Some(
        request
            .remote_access_scope
            .unwrap_or_else(|| infer_remote_access_scope(&bind_host)),
    );

    match proxy_protocol {
        PortForwardProxyProtocol::Http => {
            let local_proxy = request.local_endpoint.as_ref().ok_or_else(|| {
                AppError::InvalidInput("HTTP 网络助手需要本机代理端点".to_owned())
            })?;
            let local_host = validate_host_like(&local_proxy.host, "本机代理地址")?;
            let local_port = required_endpoint_port(local_proxy, "本机代理端口")?;
            let local_endpoint = endpoint(
                Some(local_host.clone()),
                Some(local_port),
                "本机 HTTP CONNECT 代理",
            )?;
            Ok(ForwardRoutePlan {
                kind: PortForwardKind::Remote,
                forward_arg: format!(
                    "{}:{}:{}:{}",
                    bind_host, request.source_port, local_host, local_port
                ),
                bind_host: bind_host.clone(),
                target_host: Some(local_host),
                target_port: Some(local_port),
                local_bind_host: local_endpoint
                    .as_ref()
                    .map(|endpoint| endpoint.host.clone()),
                remote_bind_host: remote_endpoint
                    .as_ref()
                    .map(|endpoint| endpoint.host.clone()),
                local_endpoint,
                remote_endpoint,
                proxy_protocol: Some(proxy_protocol),
                remote_access_scope,
                proxy_url: Some(format!(
                    "http://{}:{}",
                    format_proxy_host(&proxy_client_host(&bind_host)),
                    request.source_port
                )),
            })
        }
        PortForwardProxyProtocol::Socks5 => Ok(ForwardRoutePlan {
            kind: PortForwardKind::Remote,
            forward_arg: format!("{}:{}", bind_host, request.source_port),
            bind_host: bind_host.clone(),
            target_host: None,
            target_port: None,
            local_bind_host: None,
            remote_bind_host: remote_endpoint
                .as_ref()
                .map(|endpoint| endpoint.host.clone()),
            local_endpoint: None,
            remote_endpoint,
            proxy_protocol: Some(proxy_protocol),
            remote_access_scope,
            proxy_url: Some(format!(
                "socks5h://{}:{}",
                format_proxy_host(&proxy_client_host(&bind_host)),
                request.source_port
            )),
        }),
    }
}

fn listener_bind_host(
    preferred: Option<&str>,
    request: &PortForwardCreateRequest,
) -> AppResult<String> {
    validate_host_like(
        preferred
            .or(request.bind_host.as_deref())
            .filter(|value| !value.trim().is_empty())
            .unwrap_or("127.0.0.1"),
        "监听地址",
    )
}

fn request_bind_host(request: &PortForwardCreateRequest) -> String {
    request
        .local_bind_host
        .as_deref()
        .or(request.bind_host.as_deref())
        .filter(|value| !value.trim().is_empty())
        .unwrap_or("127.0.0.1")
        .trim()
        .to_owned()
}

fn proxy_client_host(bind_host: &str) -> String {
    match bind_host.trim() {
        "" | "0.0.0.0" => "127.0.0.1".to_owned(),
        "::" => "::1".to_owned(),
        host => host.to_owned(),
    }
}

fn format_proxy_host(host: &str) -> String {
    if host.contains(':') && !host.starts_with('[') {
        format!("[{host}]")
    } else {
        host.to_owned()
    }
}

fn endpoint(
    host: Option<String>,
    port: Option<u16>,
    label: &str,
) -> AppResult<Option<PortForwardEndpoint>> {
    let Some(host) = host else {
        return Ok(None);
    };
    Ok(Some(PortForwardEndpoint {
        host: validate_host_like(&host, label)?,
        port,
        label: Some(label.to_owned()),
    }))
}

fn required_endpoint_port(endpoint: &PortForwardEndpoint, label: &str) -> AppResult<u16> {
    match endpoint.port {
        Some(port) if port > 0 => Ok(port),
        _ => Err(AppError::InvalidInput(format!("{label}必须大于 0"))),
    }
}

fn required_target_host(request: &PortForwardCreateRequest) -> AppResult<String> {
    let target_host = request
        .target_host
        .as_deref()
        .ok_or_else(|| AppError::InvalidInput("目标主机不能为空".to_owned()))?;
    validate_host_like(target_host, "目标主机")
}

fn required_target_port(request: &PortForwardCreateRequest) -> AppResult<u16> {
    match request.target_port {
        Some(port) if port > 0 => Ok(port),
        _ => Err(AppError::InvalidInput("目标端口必须大于 0".to_owned())),
    }
}

fn validate_host_like(value: &str, label: &str) -> AppResult<String> {
    let trimmed = value.trim();
    if trimmed.is_empty()
        || trimmed.contains('\0')
        || trimmed.contains('\r')
        || trimmed.contains('\n')
        || trimmed.split_whitespace().count() > 1
    {
        return Err(AppError::InvalidInput(format!("{label}不合法")));
    }
    Ok(trimmed.to_owned())
}

fn infer_remote_access_scope(bind_host: &str) -> PortForwardRemoteAccessScope {
    let trimmed = bind_host.trim();
    if matches!(trimmed, "127.0.0.1" | "localhost" | "::1") {
        return PortForwardRemoteAccessScope::Loopback;
    }
    if matches!(trimmed, "0.0.0.0" | "::") {
        return PortForwardRemoteAccessScope::AllInterfaces;
    }
    if trimmed
        .parse::<IpAddr>()
        .ok()
        .is_some_and(|ip| matches!(ip, IpAddr::V4(ip) if ip.is_private()))
    {
        return PortForwardRemoteAccessScope::PrivateNetwork;
    }
    PortForwardRemoteAccessScope::Custom
}

pub(super) fn forward_flag(kind: PortForwardKind) -> &'static str {
    match kind {
        PortForwardKind::Local => "-L",
        PortForwardKind::Remote => "-R",
        PortForwardKind::Dynamic => "-D",
    }
}

fn normalized_name(request: &PortForwardCreateRequest, host: &RemoteHost) -> String {
    request
        .name
        .as_deref()
        .map(str::trim)
        .filter(|name| !name.is_empty())
        .map(ToOwned::to_owned)
        .unwrap_or_else(|| format!("{} {}", host.name, forward_flag(request.kind)))
}

fn command_preview(executable: &str, args: &[String]) -> String {
    std::iter::once(executable)
        .chain(args.iter().map(String::as_str))
        .map(shell_quote)
        .collect::<Vec<_>>()
        .join(" ")
}

fn shell_quote(value: &str) -> String {
    if !value.is_empty()
        && value
            .chars()
            .all(|ch| ch.is_ascii_alphanumeric() || "-_./:=@".contains(ch))
    {
        return value.to_owned();
    }
    format!("'{}'", value.replace('\'', "'\\''"))
}

//! JSONL audit log storage for non-AI events.
//!
//! @author kongweiguang

use std::{
    fs::{self, File, OpenOptions},
    io::{BufRead, BufReader, Write},
    path::{Component, Path, PathBuf},
};

use serde::{de::DeserializeOwned, Serialize};
use thiserror::Error;

#[derive(Debug, Error)]
pub enum AuditLogStoreError {
    #[error("audit log IO failed: {0}")]
    Io(#[from] std::io::Error),

    #[error("audit log JSON failed: {0}")]
    Json(#[from] serde_json::Error),

    #[error("invalid audit log path: {0}")]
    InvalidPath(String),
}

pub type AuditLogStoreResult<T> = Result<T, AuditLogStoreError>;

#[derive(Debug, Clone)]
pub struct AuditLogStore {
    root: PathBuf,
}

impl AuditLogStore {
    pub fn new(root: impl Into<PathBuf>) -> Self {
        Self { root: root.into() }
    }

    pub fn root(&self) -> &Path {
        &self.root
    }

    pub fn append_jsonl<T: Serialize>(
        &self,
        relative_path: impl AsRef<Path>,
        record: &T,
    ) -> AuditLogStoreResult<PathBuf> {
        let path = resolve_relative_path(&self.root, relative_path.as_ref())?;
        if let Some(parent) = path.parent() {
            fs::create_dir_all(parent)?;
        }
        let mut file = OpenOptions::new().create(true).append(true).open(&path)?;
        serde_json::to_writer(&mut file, record)?;
        file.write_all(b"\n")?;
        file.flush()?;
        Ok(path)
    }

    pub fn read_jsonl<T: DeserializeOwned>(
        &self,
        relative_path: impl AsRef<Path>,
    ) -> AuditLogStoreResult<JsonlRead<T>> {
        let relative_path = relative_path.as_ref();
        let path = resolve_relative_path(&self.root, relative_path)?;
        if !path.exists() {
            return Ok(JsonlRead {
                records: Vec::new(),
                diagnostics: Vec::new(),
            });
        }

        let file = File::open(&path)?;
        let mut records = Vec::new();
        let mut diagnostics = Vec::new();
        for (index, line) in BufReader::new(file).lines().enumerate() {
            let line_number = index + 1;
            let line = line?;
            if line.trim().is_empty() {
                continue;
            }
            match serde_json::from_str::<T>(&line) {
                Ok(record) => records.push(record),
                Err(error) => diagnostics.push(JsonlDiagnostic {
                    path: relative_path.to_path_buf(),
                    line_number,
                    message: error.to_string(),
                    raw_line: line,
                }),
            }
        }

        Ok(JsonlRead {
            records,
            diagnostics,
        })
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct JsonlRead<T> {
    pub records: Vec<T>,
    pub diagnostics: Vec<JsonlDiagnostic>,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct JsonlDiagnostic {
    pub path: PathBuf,
    pub line_number: usize,
    pub message: String,
    pub raw_line: String,
}

fn resolve_relative_path(root: &Path, relative_path: &Path) -> AuditLogStoreResult<PathBuf> {
    let mut clean = PathBuf::new();
    for component in relative_path.components() {
        match component {
            Component::Normal(part) => clean.push(part),
            Component::CurDir => {}
            Component::ParentDir | Component::Prefix(_) | Component::RootDir => {
                return Err(AuditLogStoreError::InvalidPath(
                    relative_path.display().to_string(),
                ));
            }
        }
    }

    if clean.as_os_str().is_empty() {
        return Err(AuditLogStoreError::InvalidPath("empty path".to_string()));
    }

    Ok(root.join(clean))
}

