fn sanitize_file_id(field: &str, value: &str) -> FileStoreResult<String> {
    let value = value.trim();
    if value.is_empty()
        || value == "."
        || value == ".."
        || value == "groups"
        || !value
            .chars()
            .all(|ch| ch.is_ascii_alphanumeric() || matches!(ch, '-' | '_' | '.'))
    {
        return Err(FileStoreError::InvalidPath(format!(
            "invalid {field}: {value}"
        )));
    }
    Ok(value.to_owned())
}

