fn assert_agent_launch_command(spec: &ExternalAgentLaunchSpec, command: &str) {
    assert_launch_parts(&spec.shell, &spec.args, command);
}

fn assert_launch_parts(shell: &str, args: &[String], command: &str) {
    #[cfg(windows)]
    {
        let expected_args = vec![
            "/d".to_owned(),
            "/s".to_owned(),
            "/k".to_owned(),
            command.to_owned(),
        ];
        assert_eq!(shell, "cmd.exe");
        assert_eq!(args, expected_args.as_slice());
    }

    #[cfg(not(windows))]
    {
        let (expected_shell, expected_args) = split_command_line(command);
        assert_eq!(shell, expected_shell);
        assert_eq!(args, expected_args);
    }
}

fn path_to_string(path: &Path) -> String {
    path.to_string_lossy().into_owned()
}

fn prepare_custom_command_spec(command: &str) -> ExternalAgentLaunchSpec {
    let temp = tempfile::tempdir().expect("tempdir");
    let service = ExternalAgentWorkspaceService::new(
        temp.path(),
        Some("http://127.0.0.1:3005/mcp".to_owned()),
        true,
    );

    service
        .prepare(&PrepareExternalAgentWorkspaceRequest {
            agent_id: "custom".to_owned(),
            agent_session_id: None,
            custom_command: Some(command.to_owned()),
            resume_provider_session: false,
            dry_run: false,
            overwrite_policy: ExternalAgentOverwritePolicy::BackupAndReplaceInvalid,
        })
        .expect("prepare custom command")
}

#[cfg(not(windows))]
fn split_command_line(input: &str) -> (String, Vec<String>) {
    let chars = input.chars().collect::<Vec<_>>();
    let mut parts = Vec::new();
    let mut current = String::new();
    let mut quote: Option<char> = None;
    let mut index = 0;

    while index < chars.len() {
        let char = chars[index];
        if char == '\\' {
            if let Some(next) = chars.get(index + 1).copied() {
                if next == '"' || next == '\'' || next == '\\' || next.is_whitespace() {
                    current.push(next);
                    index += 2;
                    continue;
                }
            }
            current.push(char);
            index += 1;
            continue;
        }
        if let Some(active_quote) = quote {
            if char == active_quote {
                quote = None;
            } else {
                current.push(char);
            }
            index += 1;
            continue;
        }
        if char == '"' || char == '\'' {
            quote = Some(char);
            index += 1;
            continue;
        }
        if char.is_whitespace() {
            if !current.is_empty() {
                parts.push(std::mem::take(&mut current));
            }
            index += 1;
            continue;
        }
        current.push(char);
        index += 1;
    }

    if !current.is_empty() {
        parts.push(current);
    }

    let shell = parts.first().cloned().expect("command shell");
    (shell, parts[1..].to_vec())
}

fn assert_session_env(
    spec: &ExternalAgentLaunchSpec,
    agent_session_id: &str,
    workspace_root: &Path,
    session_root: &Path,
    mcp_endpoint: &str,
) {
    let env = spec.env.as_ref().expect("session env");
    let expected_workspace_root = path_to_string(workspace_root);
    let expected_session_root = path_to_string(session_root);
    assert_eq!(
        env.get("KERMINAL_AGENT_SESSION_ID").map(String::as_str),
        Some(agent_session_id)
    );
    assert_eq!(
        env.get("KERMINAL_WORKSPACE_ROOT").map(String::as_str),
        Some(expected_workspace_root.as_str())
    );
    assert_eq!(
        env.get("KERMINAL_AGENT_SESSION_ROOT").map(String::as_str),
        Some(expected_session_root.as_str())
    );
    assert_eq!(
        env.get("KERMINAL_MCP_ENDPOINT").map(String::as_str),
        Some(mcp_endpoint)
    );
}

//! 本地文件对话框命令集成测试。
//!
//! @author kongweiguang

use std::fs;

use kerminal_lib::commands::file_dialog::{
    file_dialog_list_local_directory,
    path_model::{default_save_path_parts, normalize_local_path_string},
};
use tempfile::tempdir;

#[tokio::test]
async fn local_directory_listing_orders_directories_files_and_hidden_entries() {
    let root = tempdir().expect("temp dir");
    fs::create_dir_all(root.path().join("z-dir")).expect("create z dir");
    fs::create_dir_all(root.path().join("a-dir")).expect("create a dir");
    fs::write(root.path().join(".hidden-file"), "hidden").expect("write hidden file");
    fs::write(root.path().join("b-file.txt"), "file").expect("write file");

    let listing =
        file_dialog_list_local_directory(Some(root.path().to_string_lossy().into_owned()))
            .await
            .expect("list local directory");
    let names: Vec<_> = listing
        .entries
        .iter()
        .map(|entry| entry.name.as_str())
        .collect();

    assert_eq!(
        listing.path,
        normalize_windows_verbatim_path(&root.path().canonicalize().expect("canonical root"))
    );
    assert_eq!(names, vec!["a-dir", "z-dir", ".hidden-file", "b-file.txt"]);
    assert!(listing
        .entries
        .iter()
        .any(|entry| entry.name == ".hidden-file" && entry.hidden));
}

#[cfg(unix)]
#[tokio::test]
async fn local_directory_listing_reports_symlink_entries() {
    use std::os::unix::fs::symlink;

    let root = tempdir().expect("temp dir");
    fs::write(root.path().join("target.txt"), "file").expect("write target");
    symlink(
        root.path().join("target.txt"),
        root.path().join("target-link"),
    )
    .expect("create symlink");

    let listing =
        file_dialog_list_local_directory(Some(root.path().to_string_lossy().into_owned()))
            .await
            .expect("list local directory");
    let link = listing
        .entries
        .iter()
        .find(|entry| entry.name == "target-link")
        .expect("symlink entry");

    assert_eq!(link.kind, "symlink");
}

fn normalize_windows_verbatim_path(path: &std::path::Path) -> String {
    let path = path.to_string_lossy();
    path.strip_prefix(r"\\?\")
        .or_else(|| path.strip_prefix(r"\?\"))
        .map(|path| {
            path.strip_prefix(r"UNC\")
                .map(|rest| format!(r"\\{rest}"))
                .unwrap_or_else(|| path.to_owned())
        })
        .unwrap_or_else(|| path.into_owned())
}

