interface RenderSettingsToolContentOptions {
  initialSectionId?: SettingsSectionId;
  onSettingsChange?: (settings: AppSettings) => void;
  saveError?: string | null;
  saveState?: SettingsSaveState;
  settings?: AppSettings;
}

